package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }

final class CompressHoistSuite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // hoist_vars
  // =========================================================================
  test("hoist_vars".fail) {
    assertCompresses(
      input = """function a() {
            bar();
            var var1;
            var var2;
        }
        function b(anArg) {
            bar();
            var var1;
            var anArg;
        }""".stripMargin.trim,
      expected = """function a() {
            var var1, var2;  // Vars go up and are joined
            bar();
        }
        function b(anArg) {
            var var1;
            bar();
            // But vars named like arguments go away!
        }""".stripMargin.trim,
      options = AllOff.copy(
        hoistVars = true
      )
    )
  }

  // =========================================================================
  // hoist_funs
  // =========================================================================
  test("hoist_funs") {
    assertCompresses(
      input = """function a() {
            bar();
            function foo() {}
        }""".stripMargin.trim,
      expected = """function a() {
            function foo() {}  // Funs go up
            bar();
        }""".stripMargin.trim,
      options = AllOff.copy(
        hoistFuns = true
      )
    )
  }

  // =========================================================================
  // hoist_no_destructurings
  // =========================================================================
  test("hoist_no_destructurings") {
    assertCompresses(
      input = """function a([anArg]) {
            bar();
            var var1;
            var anArg;  // Because anArg is already declared, this goes away!
        }""".stripMargin.trim,
      expected = """function a([anArg]) {
            var var1;
            bar();
        }""".stripMargin.trim,
      options = AllOff.copy(
        hoistFuns = true,
        hoistVars = true
      )
    )
  }

  // =========================================================================
  // dont_hoist_var_destructurings
  // =========================================================================
  test("dont_hoist_var_destructurings") {
    assertCompresses(
      input = """function x() {
            // If foo is null or undefined, this should be an exception
            var {x,y} = foo;
        }""".stripMargin.trim,
      expected = """function x() {
            var {x,y} = foo;
        }""".stripMargin.trim,
      options = AllOff.copy(
        hoistFuns = true,
        hoistVars = true
      )
    )
  }

}
